package com.taskflow.service;

import com.taskflow.dto.TaskResponse;
import com.taskflow.dto.TransitionResponse;
import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import com.taskflow.exception.ResourceNotFoundException;
import com.taskflow.repository.TaskRepository;
import org.springframework.stereotype.Service;

import java.util.EnumMap;
import java.util.List;
import java.util.Map;

@Service
public class TaskStateMachineService {

    private static final Map<TaskStatus, List<TaskStatus>> TRANSITIONS = new EnumMap<>(TaskStatus.class);

    static {
        TRANSITIONS.put(TaskStatus.TODO, List.of(TaskStatus.IN_PROGRESS));
        TRANSITIONS.put(TaskStatus.IN_PROGRESS, List.of(TaskStatus.TODO, TaskStatus.DONE));
        TRANSITIONS.put(TaskStatus.DONE, List.of(TaskStatus.CLOSED));
        TRANSITIONS.put(TaskStatus.CLOSED, List.of());
    }

    private final TaskRepository taskRepository;

    public TaskStateMachineService(TaskRepository taskRepository) {
        this.taskRepository = taskRepository;
    }

    public TaskResponse updateStatus(Long taskId, String targetStatusStr) {
        Task task = findTask(taskId);
        TaskStatus targetStatus = TaskStatus.valueOf(targetStatusStr);
        TaskStatus currentStatus = task.getStatus();

        List<TaskStatus> allowed = TRANSITIONS.getOrDefault(currentStatus, List.of());
        if (!allowed.contains(targetStatus)) {
            throw new IllegalStateException(
                    "Invalid transition from " + currentStatus + " to " + targetStatus);
        }

        task.setStatus(targetStatus);
        Task saved = taskRepository.save(task);
        return toResponse(saved);
    }

    public TransitionResponse getAvailableTransitions(Long taskId) {
        Task task = findTask(taskId);
        List<String> available = TRANSITIONS.getOrDefault(task.getStatus(), List.of())
                .stream()
                .map(TaskStatus::name)
                .toList();
        return new TransitionResponse(task.getStatus().name(), available);
    }

    private Task findTask(Long taskId) {
        return taskRepository.findById(taskId)
                .filter(t -> !t.isDeleted())
                .orElseThrow(() -> new ResourceNotFoundException("Task not found"));
    }

    private TaskResponse toResponse(Task task) {
        TaskResponse response = new TaskResponse();
        response.setId(task.getId());
        response.setTitle(task.getTitle());
        response.setDescription(task.getDescription());
        response.setPriority(task.getPriority());
        response.setStatus(task.getStatus().name());
        response.setCreatedBy(task.getCreatedBy());
        response.setCreatedAt(task.getCreatedAt());
        response.setUpdatedAt(task.getUpdatedAt());
        return response;
    }
}

